import{_ as e,o as d,c as r,ai as o}from"./chunks/framework.CaiDwmc7.js";const h=JSON.parse('{"title":"Model Assignment Convention","description":"The strict three-tier model assignment convention — Opus for deep analysis, Sonnet for general work, Haiku for fast lookups.","frontmatter":{"title":"Model Assignment Convention","description":"The strict three-tier model assignment convention — Opus for deep analysis, Sonnet for general work, Haiku for fast lookups.","outline":[2,3]},"headers":[],"relativePath":"plugin/model-assignment.md","filePath":"plugin/model-assignment.md","lastUpdated":0}'),n={name:"plugin/model-assignment.md"};function a(i,t,s,c,l,m){return d(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="model-assignment-convention" tabindex="-1">Model Assignment Convention <a class="header-anchor" href="#model-assignment-convention" aria-label="Permalink to “Model Assignment Convention”">​</a></h1><p>The plugin follows a strict three-tier model assignment convention. Each component is assigned the cheapest model that can reliably handle its task.</p><h2 id="opus-—-deep-analysis-creative-synthesis" tabindex="-1">Opus — Deep Analysis &amp; Creative Synthesis <a class="header-anchor" href="#opus-—-deep-analysis-creative-synthesis" aria-label="Permalink to “Opus — Deep Analysis &amp; Creative Synthesis”">​</a></h2><p>Used when the task requires understanding complex relationships, generating structured documents, or making architectural decisions.</p><table tabindex="0"><thead><tr><th>Component</th><th>Type</th><th>Why Opus</th></tr></thead><tbody><tr><td><code>codebase-analyzer</code></td><td>Agent</td><td>Traces multi-file data flow, explains complex logic</td></tr><tr><td><code>prism-analyzer</code></td><td>Agent</td><td>Extracts nuanced insights from research documents</td></tr><tr><td><code>create_plan</code></td><td>Command</td><td>Generates phased plans with success criteria</td></tr><tr><td><code>iterate_plan</code></td><td>Command</td><td>Surgical plan updates requiring architectural judgment</td></tr><tr><td><code>decompose_plan</code></td><td>Command</td><td>Converts plans to dependency-ordered stories</td></tr><tr><td><code>research_codebase</code></td><td>Command</td><td>Coordinates multi-agent research campaigns</td></tr><tr><td><code>generate_prd</code></td><td>Command</td><td>Creates comprehensive product requirements</td></tr><tr><td><code>generate_pricing</code></td><td>Command</td><td>Professional pricing proposals with Gantt charts</td></tr><tr><td><code>generate_tech_spec</code></td><td>Command</td><td>API contracts, data models, architecture diagrams</td></tr><tr><td><code>generate_user_flows</code></td><td>Command</td><td>UX documentation with wireframes</td></tr><tr><td><code>prism-plan</code></td><td>Skill</td><td>Interactive planning with user feedback loops</td></tr><tr><td><code>prism-iterate</code></td><td>Skill</td><td>Plan adjustment requiring deep understanding</td></tr><tr><td><code>prism-prd</code></td><td>Skill</td><td>PRD orchestration with context awareness</td></tr><tr><td><code>prism-visual-docs</code></td><td>Skill</td><td>Visual documentation orchestration</td></tr></tbody></table><h2 id="sonnet-—-general-implementation-work" tabindex="-1">Sonnet — General Implementation Work <a class="header-anchor" href="#sonnet-—-general-implementation-work" aria-label="Permalink to “Sonnet — General Implementation Work”">​</a></h2><p>Used for straightforward execution, routing, and integration tasks that don&#39;t require deep synthesis.</p><table tabindex="0"><thead><tr><th>Component</th><th>Type</th><th>Why Sonnet</th></tr></thead><tbody><tr><td><code>codebase-pattern-finder</code></td><td>Agent</td><td>Pattern matching is systematic, not creative</td></tr><tr><td><code>web-search-researcher</code></td><td>Agent</td><td>Web research follows clear procedures</td></tr><tr><td><code>implement_plan</code></td><td>Command</td><td>Follows an existing plan — execution not design</td></tr><tr><td><code>validate_plan</code></td><td>Command</td><td>Comparison against criteria — checklist work</td></tr><tr><td><code>describe_pr</code></td><td>Command</td><td>Summarizes known diffs</td></tr><tr><td><code>create_handoff</code></td><td>Command</td><td>Structured document generation</td></tr><tr><td><code>resume_handoff</code></td><td>Command</td><td>Context reconstruction from artifacts</td></tr><tr><td><code>retroactive</code></td><td>Command</td><td>Post-hoc documentation</td></tr><tr><td><code>prism-debug</code></td><td>Command</td><td>Parallel agent coordination</td></tr><tr><td><code>prism-verify</code></td><td>Command</td><td>Browser verification coordination</td></tr><tr><td><code>prism-browse</code></td><td>Command</td><td>Interactive browser session</td></tr><tr><td>Infrastructure cmds</td><td>Commands</td><td>CLI install/uninstall, dir migration</td></tr><tr><td><code>prism</code></td><td>Skill</td><td>Master router — routes, doesn&#39;t synthesize</td></tr><tr><td><code>prism-research</code></td><td>Skill</td><td>Agent spawning coordination</td></tr><tr><td><code>prism-implement</code></td><td>Skill</td><td>Phase-by-phase execution coordination</td></tr><tr><td><code>prism-validate</code></td><td>Skill</td><td>Verification coordination</td></tr><tr><td><code>prism-debug</code></td><td>Skill</td><td>Debug agent coordination</td></tr><tr><td><code>prism-spectrum</code></td><td>Skill</td><td>Single-story execution with signal protocol</td></tr><tr><td><code>prism-verify</code></td><td>Skill</td><td>Browser verification orchestration</td></tr></tbody></table><h2 id="haiku-—-fast-lookups-simple-operations" tabindex="-1">Haiku — Fast Lookups &amp; Simple Operations <a class="header-anchor" href="#haiku-—-fast-lookups-simple-operations" aria-label="Permalink to “Haiku — Fast Lookups &amp; Simple Operations”">​</a></h2><p>Used for tasks that are fast, focused, and don&#39;t require nuanced judgment.</p><table tabindex="0"><thead><tr><th>Component</th><th>Type</th><th>Why Haiku</th></tr></thead><tbody><tr><td><code>codebase-locator</code></td><td>Agent</td><td>File location via Glob/Grep — no analysis needed</td></tr><tr><td><code>prism-locator</code></td><td>Agent</td><td>Directory scanning — mechanical task</td></tr><tr><td><code>log-investigator</code></td><td>Agent</td><td>Log file parsing — pattern matching</td></tr><tr><td><code>state-investigator</code></td><td>Agent</td><td>Environment checks — straightforward</td></tr><tr><td><code>git-investigator</code></td><td>Agent</td><td>Git log analysis — structured data</td></tr><tr><td><code>browser-verifier</code></td><td>Agent</td><td>Playwright command execution — procedural</td></tr><tr><td><code>commit</code></td><td>Command</td><td>Git commit — minimal judgment needed</td></tr><tr><td><code>worktree</code></td><td>Command</td><td>Git worktree creation — procedural</td></tr><tr><td><code>review-setup</code></td><td>Command</td><td>Branch checkout — procedural</td></tr><tr><td><code>prism-screenshot</code></td><td>Command</td><td>Single browser screenshot — trivial</td></tr></tbody></table>',11)])])}const u=e(n,[["render",a]]);export{h as __pageData,u as default};
